  COALESCE(e.rolname, 'PUBLIC') AS grantee,
  a.privilege_type,
  a.is_grantable
FROM aclexplode(acldefault('l'::"char", 'root'::regrole)) a
LEFT JOIN pg_roles g ON g.oid = a.grantor
LEFT JOIN pg_roles e ON e.oid = a.grantee
ORDER BY 1, 2, 3

