  JOIN pg_catalog.pg_type AS t ON (a.atttypid = t.oid)
  LEFT JOIN pg_catalog.pg_attrdef AS d ON
      (d.adrelid = a.attrelid AND d.adnum = a.attnum)
  JOIN (SELECT 1 AS oid, 1 AS attnum) AS vals ON
