       source_class.relname AS depends_on
FROM pg_depend d
JOIN pg_rewrite r ON d.classid = r.tableoid AND d.objid = r.oid
JOIN pg_class depend_class ON r.ev_class = depend_class.oid
JOIN pg_class source_class ON d.refobjid = source_class.oid
